/** Lazily-initialized entity lookup map. `null` until the first `lookupEntity` call triggers parsing. */
let cachedTable: Map<string, string> | null = null;

/**
 * Lazily parse the packed entity table on first use.
 *
 * Table format is `\u001f`-separated fields (name + codepoints) with `\u001e`
 * between entries. Parsing happens exactly once per process; subsequent
 * lookups go straight to the Map.
 *
 * @returns The lazily-built entity name → decoded-string map.
 */
function ensureTable(): Map<string, string> {
  if (cachedTable) return cachedTable;
  const map = new Map<string, string>();
  const entries = packed.split("\u001e");
  for (let i = 0; i < entries.length; i++) {
    decodeEntry(entries[i] ?? "", map);
  }
  cachedTable = map;
  return map;
}

/**
 * Decode one packed entry and insert it into the target map.
 *
 * Empty-name records from a malformed table are silently skipped.
 */
function decodeEntry(entry: string, map: Map<string, string>): void {
  if (entry.length === 0) return;
  const parts = entry.split("\u001f");
  const name = parts[0] ?? "";
  if (name.length === 0) return;
  let decoded = "";
  for (let j = 1; j < parts.length; j++) {
    const codepointText = parts[j];
    if (codepointText === undefined) continue;
    decoded += String.fromCodePoint(Number.parseInt(codepointText, 10));
  }
  map.set(name, decoded);
}

/**
 * Look up a named entity by bare name (without & or ;).
 *
 * @param name - Entity name such as `amp`, `copy`, `HilbertSpace`.
 * @returns Decoded Unicode string, or null when the name is not in the table.
 *   Empty input returns null.
 */
export function lookupEntity(name: string): string | null {
  if (name.length === 0) return null;
  return ensureTable().get(name) ?? null;
}
